285	}
286	.heatmap tfoot td:first-child { position: sticky; left: 0; z-index: 30; background: var(--bg-thead); }
287	.heatmap tfoot td:last-child  { position: sticky; right: 0; z-index: 30; background: var(--bg-thead); border-left: 2px solid var(--border); }
288	
289	/* --- Status ------------------------------------------------------------- */
290	
291	.status-msg {
292	    display: flex; align-items: center; justify-content: center;
293	    height: 100%; min-height: 200px; font-size: 13px; color: var(--text-muted);
294	}
295	.status-msg.error { color: var(--accent-red); }
296	.spinner {
297	    display: inline-block; width: 16px; height: 16px;
298	    border: 2px solid var(--border); border-top-color: var(--accent-cyan);
299	    border-radius: 50%; animation: spin 0.5s linear infinite; margin-right: 8px;
300	}
301	@keyframes spin { to { transform: rotate(360deg); } }
302	
303	/* --- Settings Modal ----------------------------------------------------- */
304	
305	.modal-overlay {
306	    display: none; position: fixed; inset: 0; z-index: 1000;
307	    background: rgba(0,0,0,0.6); backdrop-filter: blur(4px);
308	    align-items: center; justify-content: center;
309	}
310	.modal-overlay.open { display: flex; }
311	
312	.modal {
313	    background: var(--bg-modal); border: 1px solid var(--border-strong);
314	    border-radius: 10px; padding: 24px 28px; width: 520px; max-height: 85vh; overflow-y: auto;
315	}
316	.modal h2 {
317	    font-family: var(--font-sans); font-size: 16px; font-weight: 700;
318	    color: var(--text-bright); margin-bottom: 16px;
319	}
320	
321	.modal__section-title {
322	    font-family: var(--font-sans); font-size: 11px; font-weight: 600;
323	    text-transform: uppercase; letter-spacing: 0.06em;
324	    color: var(--text-muted); margin: 18px 0 10px;
325	    padding-bottom: 6px; border-bottom: 1px solid var(--border);
326	}
327	
328	/* Color tier row */
329	.tier-row {
330	    display: grid;
331	    grid-template-columns: 1fr 50px 50px;
332	    align-items: center;
333	    gap: 10px;
334	    margin-bottom: 10px;
335	    padding: 8px 10px;
336	    border-radius: 6px;
337	    background: var(--bg-input);
338	}
339	.tier-row__label {
340	    font-size: 12px;
341	    color: var(--text-primary);
342	}
343	.tier-row__sublabel {
344	    font-size: 10px;
345	    color: var(--text-muted);
346	    margin-top: 1px;
347	}
348	.tier-row__col-head {
349	    font-size: 10px;
350	    color: var(--text-muted);
351	    text-align: center;
352	    font-weight: 600;
353	    text-transform: uppercase;
354	    letter-spacing: 0.04em;
355	}
356	
357	.color-input {
358	    width: 40px; height: 26px;
359	    border: 1px solid var(--border); border-radius: 4px;
360	    background: var(--bg-widget); cursor: pointer; padding: 2px;
361	}
362	
363	/* Threshold slider row */
364	.modal__row {
365	    display: flex;
366	    align-items: center;
367	    justify-content: space-between;
368	    margin-bottom: 12px;
369	}
370	.modal__label { font-size: 12px; color: var(--text-secondary); }
371	.modal__range { width: 160px; accent-color: var(--accent-cyan); }
372	.modal__range-val {
373	    font-size: 11px; color: var(--text-muted); width: 40px;
374	    text-align: right; font-variant-numeric: tabular-nums;
375	}
